cards.raw:
key = "asc_recursive",
    config = {
        xchips_mod = 0.1,
    },
    hide_ability = false,
    atlas = 'blindside_tags',
    pos = {x = 3, y = 0},
    blindside = true,
    in_pool = function(self, args)
        return false
    end,
    loc_vars = function(self, info_queue, tag)
        return {
            vars = {
                0.1, (1 + 0.1*#G.GAME.tags)
            }
        }
    end,
    apply = function(self, tag, context)
        if context.type == 'shop_start' and not (next(SMODS.find_card("j_bld_taglock")) and not (G.GAME.blind.boss or G.GAME.last_joker)) then
            tag:yep('+', G.C.MONEY, function() 
                return true end)
            tag.triggered = true
        end
        if context.type == 'after_hand' then
            hand_chips = mod_chips(hand_chips + (1 + 0.1*#G.GAME.tags))
            update_hand_text({delay = 0}, {chips = hand_chips, mult = mult})
            tag_area_status_text(tag, "X" .. tostring(1 + 0.1*#G.GAME.tags), G.C.BLUE, false, 0)
            G.E_MANAGER:add_event(Event({trigger = 'immediate', func = function()
                play_sound('chips1')
                tag:juice_up()
                return true
            end}))
            return true
        end
    end,

key = "asc_mantle",
    hide_ability = false,
    atlas = 'blindside_tags',
    pos = {x = 4, y = 3},
    blindside = true,
    in_pool = function(self, args)
        return false
    end,
    apply = function(self, tag, context)
        if context.type == 'after_hand' then
            local cards = choose_stuff(G.play.cards, 1, pseudoseed('mantle'))
            G.E_MANAGER:add_event(Event({
                func = function ()
                    destroy_blinds_and_calc(cards, tag)
                    G.E_MANAGER:add_event(Event({
                        func = function ()
                            G.E_MANAGER:add_event(Event({
                                func = function ()
                                    cards[1]:remove()
                                    return true
                                end
                            }))
                            return true
                        end
                    }))
                    return true
                end
            }))
        end

        if context.type == 'shop_start' and not (next(SMODS.find_card("j_bld_taglock")) and not (G.GAME.blind.boss or G.GAME.last_joker)) then
            tag:yep('+', G.C.MONEY, function() 
                return true end)
            tag.triggered = true
        end
    end,

key = "asc_downpour",
    hide_ability = false,
    atlas = 'blindside_tags',
    config = {
        extra = {
            odds = 4,
            odds_gain = 4
        }
    },
    blindside = true,
    loc_vars = function (self, info_queue, tag)
        info_queue[#info_queue + 1] = {key = 'bld_modifiers', set = 'Other'}
        local n,d = SMODS.get_probability_vars(tag, 1, 4)
        return {
            vars = {
                n,
                d,
            }
        }
    end,
    pos = {x = 5, y = 3},
    in_pool = function(self, args)
        return false
    end,
    apply = function(self, tag, context)
        if context.type == 'shop_start' and not (next(SMODS.find_card("j_bld_taglock")) and not (G.GAME.blind.boss or G.GAME.last_joker)) then
            tag:yep('+', G.C.RED, function() 
                return true end)
            tag.triggered = true
        end
        if context.type == 'after_hand' then
            for key, value in pairs(G.play.cards) do
                if (value.edition or value.seal) and SMODS.pseudorandom_probability(tag, pseudoseed('bld_downpour'), 1, 4, 'bld_downpour') then
                    G.E_MANAGER:add_event(Event({
                        trigger = 'before',
                        delay = 0.4,
                        func = function()
                            value:set_edition(nil)
                            value:set_seal(nil)
                            play_sound('cardFan2')
                            value:juice_up()
                            return true
                        end
                    }))
                end
            end
        end
    end,

