name="", key="planetlua",sprite_pos={x=8,y=2}, new_key="starlua", prefix = "cry",config = {
    level = 1,
    odds = 5
  },
  loc_vars = function(self,q,card) 
    Entropy.ensure_ascpow_tutorial(q)
    local numerator, denominator = SMODS.get_probability_vars(card, 1, card.ability.odds)
    return {
      vars = {
        numerator,
        denominator,
        card.ability.level,
      }
    }
  end,
  func = function(self,card,area,copier,number)
    if number and number ~= 1 then
      Entropy.star_lua_bulk(self,card,area,copier,number)
    else
      Entropy.star_lua_single(self,card,area,copier)
    end
  end,
  calc = function(self, card, context)
    if
      G.GAME.used_vouchers.v_observatory
      and context.joker_main
      and (
        context.scoring_name == card.ability.handname
      )
      and pseudorandom("starlua") < 0.25
    then
      local value = G.P_CENTERS.v_observatory.config.extra
      return {
        x_asc = to_big(value) ^ (card.ability.overflow_amount or 1),
      }
    end
  end

